// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task Card sub-component
function TaskCard({
  task,
  onEdit,
  onMove,
}: {
  task: Props['tasks'][0];
  onEdit: (title: string) => void;
  onMove: (columnId: string) => void;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleSaveEdit = () => {
    if (editTitle.trim()) {
      onEdit(editTitle);
      setIsEditing(false);
    }
  };

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-100)';
      case 'medium':
        return 'var(--ggui-color-warning-100)';
      case 'low':
        return 'var(--ggui-color-success-100)';
      default:
        return 'var(--ggui-color-surfaceVariant)';
    }
  };

  const getPriorityBadgeVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {/* Task Title */}
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-1)" direction="horizontal" align="center">
            <Input
              label="Edit task"
              value={editTitle}
              onChange={setEditTitle}
              placeholder="Task title"
            />
            <Button size="sm" variant="primary" onClick={handleSaveEdit}>
              Save
            </Button>
          </Stack>
        ) : (
          <Text
            as={Clickable}
            onClick={() => setIsEditing(true)}
            variant="body"
            weight="medium"
            style={{ cursor: 'pointer' }}
          >
            {task.title || 'Untitled'}
          </Text>
        )}

        {/* Priority Badge */}
        {task.priority && (
          <Badge variant={getPriorityBadgeVariant(task.priority) as any} size="sm">
            {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
          </Badge>
        )}

        {/* Assignee & Due Date */}
        <Row gap="var(--ggui-spacing-2)" align="center">
          {task.assignee && (
            <Avatar name={task.assignee} size="sm" shape="circle" />
          )}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {new Date(task.dueDate).toLocaleDateString()}
            </Text>
          )}
        </Row>

        {/* Move Button/Dropdown */}
        <Dropdown
          trigger={<Button size="sm" variant="outline">Move</Button>}
          options={[
            { value: 'todo', label: 'To Do' },
            { value: 'in-progress', label: 'In Progress' },
            { value: 'done', label: 'Done' },
          ].filter(col => col.value !== task.column)}
          value=""
          onChange={(col) => onMove(col)}
          placement="bottom-start"
        />
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state
  const [tasks, setTasks] = useState<Props['tasks']>(props.tasks || []);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [addingTaskToColumn, setAddingTaskToColumn] = useState<string | null>(null);

  // Sync tasks from props and stream updates
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks(prev => [...prev, task]);
      } else if (action === 'move' && task) {
        setTasks(prev => prev.map(t => t.id === task.id ? { ...t, column: task.column } : t));
      } else if (action === 'edit' && task) {
        setTasks(prev => prev.map(t => t.id === task.id ? { ...t, ...task } : t));
      } else if (action === 'delete' && task) {
        setTasks(prev => prev.filter(t => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string | undefined, toColumn: string) => {
    if (!taskId) return;
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: toColumn } : t));
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string | undefined, newTitle: string) => {
    if (!taskId) return;
    taskUpdate({ action: 'edit', taskId, data: { column: 'temp' } });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
  }, [taskUpdate]);

  const handleAddTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask: Props['tasks'][0] = {
      id: `task-${Date.now()}`,
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
    };
    taskUpdate({ action: 'create', taskId: newTask.id!, data: { column: columnId } });
    setTasks(prev => [...prev, newTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingTaskToColumn(null);
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Compute tasks per column
  const tasksByColumn = useMemo(() => {
    const map: Record<string, Props['tasks']> = {};
    (props.columns || []).forEach(col => {
      map[col.id || ''] = [];
    });
    tasks.forEach(task => {
      const colId = task.column || 'todo';
      if (!map[colId]) map[colId] = [];
      map[colId].push(task);
    });
    return map;
  }, [tasks, props.columns]);

  // Compute summary
  const summary = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter(t => t.column === 'done').length;
    return { total, completed };
  }, [tasks]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" background="var(--ggui-color-primary-50)">
          <Row gap="var(--ggui-spacing-6)" align="center" justify="between">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-primary-700)">
                Task Summary
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                {summary.completed} of {summary.total} tasks completed
              </Text>
            </Stack>
            <Progress
              value={summary.total > 0 ? (summary.completed / summary.total) * 100 : 0}
              variant="success"
              size="md"
              style={{ width: '200px' }}
            />
          </Row>
        </Card>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" direction="horizontal" align="start">
          {(props.columns || []).map(column => {
            const colId = column.id || '';
            const colTasks = tasksByColumn[colId] || [];

            return (
              <Box
                key={colId}
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-lg)"
                style={{ flex: '1 1 300px', minHeight: '600px' }}
              >
                <Stack gap="var(--ggui-spacing-4)" style={{ height: '100%' }}>
                  {/* Column Header */}
                  <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                    <Stack gap="var(--ggui-spacing-1)" direction="horizontal" align="center">
                      <Heading level={4} color="var(--ggui-color-onSurface)">
                        {column.name || 'Column'}
                      </Heading>
                      <Badge variant="default" size="sm">
                        {colTasks.length}
                      </Badge>
                    </Stack>
                  </Row>

                  {/* Tasks List */}
                  <Stack gap="var(--ggui-spacing-3)" style={{ flex: 1 }}>
                    {colTasks.map(task => (
                      <TaskCard
                        key={task.id}
                        task={task}
                        onEdit={(newTitle) => handleEditTask(task.id, newTitle)}
                        onMove={(toCol) => handleMoveTask(task.id, toCol)}
                      />
                    ))}
                  </Stack>

                  {/* Add Task Section */}
                  <Spacer size="flex" />
                  {addingTaskToColumn === colId ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" border={true}>
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)" direction="horizontal">
                          <Button
                            size="sm"
                            variant="primary"
                            onClick={() => handleAddTask(colId)}
                          >
                            Add Task
                          </Button>
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => {
                              setAddingTaskToColumn(null);
                              setNewTaskTitle('');
                            }}
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
                      size="md"
                      fullWidth
                      onClick={() => setAddingTaskToColumn(colId)}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
}
